#include <iostream>

int add(int x, int y)
{
    return x + y;
}

int subtract(int x, int y)
{
    return x - y;
}

int applyOperation(int x, int y, int(*op)(int, int))
{
    return op(x, y);
}

int main()
{
    int a{};
    int b{};
    char op{};
    std::cin >> a >> b >> op;

    int(*fn)(int, int){ &add };
    if (op == '-')
        fn = &subtract;

    std::cout << applyOperation(a, b, fn) << '\n';

    return 0;
}

